/* ─── Styles ─────────────────────────────────────────────────── */
const css = `
  .rd-header { background:linear-gradient(135deg,#ef4444 0%,#b91c1c 100%); border-radius:14px; padding:26px 28px; margin-bottom:20px; box-shadow:0 4px 20px rgba(239,68,68,.2); }
  .rd-avatar  { width:52px; height:52px; border-radius:12px; background:rgba(255,255,255,.2); border:2px solid rgba(255,255,255,.35); display:flex; align-items:center; justify-content:center; font-weight:800; font-size:20px; color:#fff; flex-shrink:0; }
  .rd-badge   { display:inline-flex; align-items:center; gap:5px; background:rgba(255,255,255,.18); color:#fff; border:1px solid rgba(255,255,255,.28); border-radius:20px; padding:3px 10px; font-size:11px; font-weight:500; }

  .rd-stat { background:#fff; border-radius:10px; border:1px solid #e8edf2; box-shadow:0 1px 3px rgba(0,0,0,.04); padding:14px 12px; text-align:center; }
  .rd-stat-icon { width:34px; height:34px; border-radius:9px; display:flex; align-items:center; justify-content:center; margin:0 auto 8px; }
  .rd-stat-val  { font-size:14px; font-weight:700; color:#0f172a; line-height:1.2; }
  .rd-stat-lbl  { font-size:10px; color:#94a3b8; margin-top:2px; }

  .rd-card    { background:#fff; border-radius:12px; border:1px solid #e8edf2; box-shadow:0 1px 3px rgba(0,0,0,.04); overflow:hidden; }
  .rd-card-hd { padding:12px 18px; border-bottom:1px solid #f1f5f9; font-weight:600; font-size:13px; color:#0f172a; display:flex; align-items:center; gap:8px; }
  .rd-card-hd svg { color:#ef4444; }
  .rd-card-bd { padding:6px 18px 14px; }

  .rd-row { padding:10px 0; border-bottom:1px solid #f8fafc; display:flex; flex-direction:column; }
  .rd-row:last-child { border-bottom:none; }
  .rd-lbl { font-size:10px; font-weight:600; color:#94a3b8; text-transform:uppercase; letter-spacing:.05em; margin-bottom:3px; }
  .rd-val { font-size:13px; color:#334155; line-height:1.6; }
  .rd-val.empty { color:#cbd5e1; font-style:italic; }

  /* Tabs */
  .rd-tabs { display:flex; gap:4px; flex-wrap:wrap; background:#fff; border-radius:12px 12px 0 0; padding:0 16px; border:1px solid #e8edf2; border-bottom:none; }
  .rd-tab { border:none; background:transparent; padding:12px 16px; font-size:13px; font-weight:500; color:#64748b; cursor:pointer; border-bottom:2px solid transparent; margin-bottom:-1px; display:flex; align-items:center; gap:6px; transition:color .15s,border-color .15s; }
  .rd-tab:hover { color:#ef4444; }
  .rd-tab.active { color:#ef4444; border-bottom-color:#ef4444; font-weight:600; }
  .rd-tab-body { background:#fff; border:1px solid #e8edf2; border-top:none; border-radius:0 0 12px 12px; padding:20px; }

  /* Table */
  .rd-tbl-wrap { width:100%; overflow-x:auto; -webkit-overflow-scrolling:touch; }
  .rd-tbl { width:100%; border-collapse:collapse; font-size:13px; min-width:600px; }
  .rd-tbl th { background:#f8fafc; padding:10px 14px; text-align:left; font-size:10px; font-weight:700; color:#64748b; text-transform:uppercase; letter-spacing:.05em; border-bottom:1px solid #e8edf2; }
  .rd-tbl td { padding:12px 14px; border-bottom:1px solid #f8fafc; color:#334155; vertical-align:middle; }
  .rd-tbl tr:last-child td { border-bottom:none; }
  .rd-tbl tr:hover td { background:#fafafa; }
  .rd-tbl tfoot td { background:#f8fafc; font-weight:700; padding:10px 14px; font-size:12px; }

  /* Pills */
  .pill { display:inline-flex; align-items:center; gap:5px; border-radius:20px; padding:3px 10px; font-size:11px; font-weight:600; white-space:nowrap; }
  .pill::before { content:''; width:5px; height:5px; border-radius:50%; background:currentColor; flex-shrink:0; }
  .pill-green  { background:#dcfce7; color:#15803d; }
  .pill-gray   { background:#f1f5f9; color:#475569; }
  .pill-amber  { background:#fef3c7; color:#92400e; }
  .pill-blue   { background:#dbeafe; color:#1d4ed8; }
  .pill-purple { background:#ede9fe; color:#6d28d9; }
  .pill-red    { background:#fee2e2; color:#b91c1c; }

  /* Progress */
  .rd-progress-track { height:8px; background:#f1f5f9; border-radius:8px; width:100%; margin-top:6px; }
  .rd-progress-fill  { height:100%; border-radius:8px; transition:width .4s; }

  /* Avatar */
  .rd-inv-avatar { width:32px; height:32px; border-radius:8px; background:#fff5f5; color:#ef4444; display:flex; align-items:center; justify-content:center; font-weight:700; font-size:12px; flex-shrink:0; }

  /* Doc item */
  .rd-doc { display:flex; align-items:center; gap:12px; padding:11px 0; border-bottom:1px solid #f8fafc; }
  .rd-doc:last-child { border-bottom:none; }
  .rd-doc-icon { width:36px; height:36px; border-radius:8px; display:flex; align-items:center; justify-content:center; flex-shrink:0; }
  .rd-doc-name { font-size:13px; font-weight:500; color:#0f172a; }
  .rd-doc-meta { font-size:11px; color:#94a3b8; margin-top:2px; }
  .rd-dl-btn { display:inline-flex; align-items:center; gap:5px; padding:5px 12px; background:#fff5f5; color:#ef4444; border:1px solid #fecaca; border-radius:8px; font-size:11px; font-weight:600; cursor:pointer; text-decoration:none; transition:background .15s; }
  .rd-dl-btn:hover { background:#fee2e2; color:#b91c1c; }

  /* Timeline */
  .rd-timeline { position:relative; padding-left:28px; }
  .rd-timeline::before { content:''; position:absolute; left:9px; top:6px; bottom:6px; width:1.5px; background:#f1f5f9; }
  .rd-tl-item { position:relative; margin-bottom:20px; }
  .rd-tl-item:last-child { margin-bottom:0; }
  .rd-tl-dot { position:absolute; left:-24px; top:3px; width:12px; height:12px; border-radius:50%; border:2px solid #fff; box-shadow:0 0 0 1.5px currentColor; flex-shrink:0; }
  .rd-tl-dot.green  { color:#22c55e; background:#dcfce7; }
  .rd-tl-dot.red    { color:#ef4444; background:#fee2e2; }
  .rd-tl-dot.blue   { color:#3b82f6; background:#dbeafe; }
  .rd-tl-dot.amber  { color:#f59e0b; background:#fef3c7; }
  .rd-tl-dot.gray   { color:#94a3b8; background:#f1f5f9; }
  .rd-tl-title { font-size:13px; font-weight:600; color:#0f172a; }
  .rd-tl-desc  { font-size:12px; color:#64748b; margin-top:2px; }
  .rd-tl-date  { font-size:11px; color:#94a3b8; margin-top:3px; }

  /* Cap table bar */
  .rd-cap-bar { height:6px; background:#f1f5f9; border-radius:4px; }
  .rd-cap-fill { height:100%; border-radius:4px; }
`;

